import{_ as s,o as n,c as t,a4 as e}from"./chunks/framework.BDOgl-CJ.js";const u=JSON.parse('{"title":"卷积（Convolution）","description":"","frontmatter":{},"headers":[],"relativePath":"ai-learning-notes/convolution.md","filePath":"ai-learning-notes/convolution.md","lastUpdated":1779253957000}'),p={name:"ai-learning-notes/convolution.md"};function l(i,a,o,d,r,h){return n(),t("div",null,[...a[0]||(a[0]=[e(`<h1 id="卷积-convolution" tabindex="-1">卷积（Convolution） <a class="header-anchor" href="#卷积-convolution" aria-label="Permalink to &quot;卷积（Convolution）&quot;">​</a></h1><h2 id="是什么" tabindex="-1">是什么 <a class="header-anchor" href="#是什么" aria-label="Permalink to &quot;是什么&quot;">​</a></h2><p>卷积就是把一个「滤镜」在数据上滑动，每一步做一次加权求和。</p><h2 id="直观理解" tabindex="-1">直观理解 <a class="header-anchor" href="#直观理解" aria-label="Permalink to &quot;直观理解&quot;">​</a></h2><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>原始信号:  [3, 7, 2, 5, 8, 1, 6]</span></span>
<span class="line"><span>卷积核:    [⅓, ⅓, ⅓]  （3 天平均窗口）</span></span>
<span class="line"><span></span></span>
<span class="line"><span>滑过去 →</span></span>
<span class="line"><span>位置0: (3×⅓ + 7×⅓ + 2×⅓) = 4.0</span></span>
<span class="line"><span>位置1: (7×⅓ + 2×⅓ + 5×⅓) = 4.67</span></span>
<span class="line"><span>位置2: (2×⅓ + 5×⅓ + 8×⅓) = 5.0</span></span>
<span class="line"><span>位置3: (5×⅓ + 8×⅓ + 1×⅓) = 4.67</span></span>
<span class="line"><span>位置4: (8×⅓ + 1×⅓ + 6×⅓) = 5.0</span></span>
<span class="line"><span></span></span>
<span class="line"><span>结果: [4.0, 4.67, 5.0, 4.67, 5.0]  ← 平滑后的曲线</span></span></code></pre></div><h2 id="数学定义" tabindex="-1">数学定义 <a class="header-anchor" href="#数学定义" aria-label="Permalink to &quot;数学定义&quot;">​</a></h2><p>(f ∗ g)(t) = ∫ f(τ) · g(t-τ) dτ</p><p>把 g 翻过来，在 f 上滑动，每步算重叠部分的积分。</p><h2 id="在图像处理-cnn-里" tabindex="-1">在图像处理（CNN）里 <a class="header-anchor" href="#在图像处理-cnn-里" aria-label="Permalink to &quot;在图像处理（CNN）里&quot;">​</a></h2><p>拿一张图片，用小矩阵（卷积核）在上面滑动：</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>图片（5×5）:              卷积核（检测竖边）:</span></span>
<span class="line"><span>┌─────────────────┐      ┌──────────┐</span></span>
<span class="line"><span>│ 10 10 10  0  0 │      │  1  0 -1 │</span></span>
<span class="line"><span>│ 10 10 10  0  0 │  ∗   │  1  0 -1 │</span></span>
<span class="line"><span>│ 10 10 10  0  0 │      │  1  0 -1 │</span></span>
<span class="line"><span>└─────────────────┘      └──────────┘</span></span>
<span class="line"><span></span></span>
<span class="line"><span>在明暗交界处（10 → 0），卷积输出值很大 → 检测到了竖边</span></span></code></pre></div><p>不同的卷积核能检测不同特征：竖边、横边、模糊、锐化……</p><h2 id="一句话" tabindex="-1">一句话 <a class="header-anchor" href="#一句话" aria-label="Permalink to &quot;一句话&quot;">​</a></h2><p>卷积 = 拿一个滤镜在数据上滑动，每步加权求和。</p><table tabindex="0"><thead><tr><th>领域</th><th>滤镜是什么</th></tr></thead><tbody><tr><td>信号处理</td><td>平滑窗口</td></tr><tr><td>图像处理</td><td>边缘检测器</td></tr><tr><td>CNN</td><td>网络自己学出来的特征提取器</td></tr></tbody></table><hr><h2 id="cnn-的设计来自猫实验" tabindex="-1">CNN 的设计来自猫实验 <a class="header-anchor" href="#cnn-的设计来自猫实验" aria-label="Permalink to &quot;CNN 的设计来自猫实验&quot;">​</a></h2><h3 id="hubel-wiesel-1959年-诺贝尔奖" tabindex="-1">Hubel &amp; Wiesel（1959年，诺贝尔奖） <a class="header-anchor" href="#hubel-wiesel-1959年-诺贝尔奖" aria-label="Permalink to &quot;Hubel &amp; Wiesel（1959年，诺贝尔奖）&quot;">​</a></h3><p>两位神经科学家把猫固定，在屏幕上打光，同时用电极<strong>记录猫视觉皮层里单个神经元的放电</strong>。</p><p>发现了两件事：</p><p><strong>1. 每个神经元只对视野里的一小块区域有反应（局部感知）</strong></p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>整张图：🖼️</span></span>
<span class="line"><span>这个神经元只管这里：[ 3×3 小块 ]</span></span>
<span class="line"><span>对其他区域的刺激：没反应</span></span></code></pre></div><p><strong>2. 神经元分层响应，从简单到复杂</strong></p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>第一层神经元 → 只识别&quot;某个角度的边缘&quot;</span></span>
<span class="line"><span>第二层神经元 → 识别&quot;边缘组合成的形状&quot;</span></span>
<span class="line"><span>第三层神经元 → 识别&quot;形状组合成的物体（比如猫耳朵）&quot;</span></span></code></pre></div><h3 id="直接启发了-cnn-的两个核心设计" tabindex="-1">直接启发了 CNN 的两个核心设计 <a class="header-anchor" href="#直接启发了-cnn-的两个核心设计" aria-label="Permalink to &quot;直接启发了 CNN 的两个核心设计&quot;">​</a></h3><table tabindex="0"><thead><tr><th>神经科学发现</th><th>CNN 对应设计</th></tr></thead><tbody><tr><td>神经元只管一小块（局部感知）</td><td>小窗口（3×3）在图片上滑动，不看全图</td></tr><tr><td>从边缘→形状→物体的层级结构</td><td>多层卷积，浅层提取边缘，深层识别物体</td></tr></tbody></table><p>CNN 的发明者 Yann LeCun 在论文和演讲里多次明确承认，CNN 设计直接来自这个猫实验。</p><p><strong>不是比喻，是真的从猫身上得出来的。</strong></p><hr><h2 id="微电极记录-怎么-听-神经元说话" tabindex="-1">微电极记录：怎么&quot;听&quot;神经元说话 <a class="header-anchor" href="#微电极记录-怎么-听-神经元说话" aria-label="Permalink to &quot;微电极记录：怎么&quot;听&quot;神经元说话&quot;">​</a></h2><h3 id="神经元放电的本质是电信号" tabindex="-1">神经元放电的本质是电信号 <a class="header-anchor" href="#神经元放电的本质是电信号" aria-label="Permalink to &quot;神经元放电的本质是电信号&quot;">​</a></h3><p>神经元&quot;放电&quot;时，细胞内外离子快速交换，产生约 <strong>100 毫伏</strong>的电压脉冲，向外辐射：</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>神经元静息：  -70mV</span></span>
<span class="line"><span>神经元放电：  +40mV  ← 这个瞬间变化就是&quot;放电&quot;</span></span>
<span class="line"><span>              ↓</span></span>
<span class="line"><span>              -70mV  恢复（约 1 毫秒）</span></span></code></pre></div><h3 id="电极怎么捡到这个信号" tabindex="-1">电极怎么捡到这个信号 <a class="header-anchor" href="#电极怎么捡到这个信号" aria-label="Permalink to &quot;电极怎么捡到这个信号&quot;">​</a></h3><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>头骨 → 开一个小孔</span></span>
<span class="line"><span>  ↓</span></span>
<span class="line"><span>微电极（尖端直径几微米，比细胞还小）插入视觉皮层</span></span>
<span class="line"><span>  ↓</span></span>
<span class="line"><span>电极尖端靠近单个神经元</span></span>
<span class="line"><span>  ↓</span></span>
<span class="line"><span>神经元放电 → 电压变化被电极捕获</span></span>
<span class="line"><span>  ↓</span></span>
<span class="line"><span>放大器 → 计算机记录 / 扬声器发出&quot;噼啪&quot;声</span></span></code></pre></div><p>每次神经元放电，扬声器就响一声。Hubel 和 Wiesel 就是<strong>靠听声音</strong>来判断哪个视觉刺激让神经元兴奋。</p><h3 id="实验现场的意外发现" tabindex="-1">实验现场的意外发现 <a class="header-anchor" href="#实验现场的意外发现" aria-label="Permalink to &quot;实验现场的意外发现&quot;">​</a></h3><p>猫被麻醉固定，眼睛对着屏幕，头骨打开小孔，电极缓慢推进去。</p><p>他们一直找不到能让神经元响的图案，沮丧了很久。后来<strong>在换幻灯片时，玻璃片的边缘划过屏幕</strong>，神经元突然疯狂放电。</p><p>这才发现：神经元响应的不是光点，而是<strong>特定角度移动的边缘</strong>。</p><p>这个技术叫<strong>微电极记录（Microelectrode Recording）</strong>，今天仍是神经科学最基础的工具之一。</p><hr><h2 id="这个实验可以在人身上做吗" tabindex="-1">这个实验可以在人身上做吗 <a class="header-anchor" href="#这个实验可以在人身上做吗" aria-label="Permalink to &quot;这个实验可以在人身上做吗&quot;">​</a></h2><h3 id="皮肤表面-完全可以-非常常见" tabindex="-1">皮肤表面：完全可以，非常常见 <a class="header-anchor" href="#皮肤表面-完全可以-非常常见" aria-label="Permalink to &quot;皮肤表面：完全可以，非常常见&quot;">​</a></h3><p>把电极贴在皮肤上，捡取从深处透出来的电信号：</p><table tabindex="0"><thead><tr><th>技术</th><th>电极位置</th><th>测什么</th></tr></thead><tbody><tr><td><strong>EEG</strong>（脑电图）</td><td>头皮表面</td><td>大脑整体电活动</td></tr><tr><td><strong>EMG</strong>（肌电图）</td><td>肌肉表面皮肤</td><td>肌肉收缩信号</td></tr><tr><td><strong>ECG</strong>（心电图）</td><td>胸部皮肤</td><td>心脏电信号</td></tr></tbody></table><p>去医院做的心电图、脑电图就是这个原理，完全无创。</p><h3 id="皮肤表面的根本局限" tabindex="-1">皮肤表面的根本局限 <a class="header-anchor" href="#皮肤表面的根本局限" aria-label="Permalink to &quot;皮肤表面的根本局限&quot;">​</a></h3><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>单个神经元的信号  ← 微电极才能捡到</span></span>
<span class="line"><span>皮肤表面捡到的    ← 数百万神经元叠加后的总和</span></span>
<span class="line"><span></span></span>
<span class="line"><span>就像：</span></span>
<span class="line"><span>  单个人说话    ← Hubel &amp; Wiesel 的微电极</span></span>
<span class="line"><span>  整个体育场的噪声  ← EEG 头皮电极</span></span></code></pre></div><h3 id="活人身上的单神经元记录" tabindex="-1">活人身上的单神经元记录 <a class="header-anchor" href="#活人身上的单神经元记录" aria-label="Permalink to &quot;活人身上的单神经元记录&quot;">​</a></h3><p>在以下医疗场景会做：</p><ul><li><strong>癫痫手术</strong>：术中微电极定位异常放电区域</li><li><strong>帕金森深脑刺激（DBS）</strong>：植入电极持续抑制震颤</li><li><strong>脑机接口（BCI）</strong>：Neuralink 在人脑植入几百根微电极，读取信号控制设备</li></ul><h3 id="动物实验的伦理代价" tabindex="-1">动物实验的伦理代价 <a class="header-anchor" href="#动物实验的伦理代价" aria-label="Permalink to &quot;动物实验的伦理代价&quot;">​</a></h3><p>Hubel 和 Wiesel 的猫实验中，猫被麻醉固定、开颅插电极，实验结束后通常被安乐死。这个拿了诺贝尔奖的发现，代价是大量动物的生命。</p><p>科学界后来提出 <strong>3R 原则</strong>约束动物实验：</p><table tabindex="0"><thead><tr><th>原则</th><th>含义</th></tr></thead><tbody><tr><td><strong>Replace</strong>（替代）</td><td>能用计算机模型或细胞实验代替就代替</td></tr><tr><td><strong>Reduce</strong>（减少）</td><td>尽量用最少的动物数量</td></tr><tr><td><strong>Refine</strong>（改善）</td><td>尽量减少痛苦，改善实验过程</td></tr></tbody></table><p>知识的获取是否可以用另一个生命的痛苦来换——这个问题科学界至今没有统一答案，只是在不断收紧边界。</p><hr><h2 id="卷积可以从其他地方独立推导出来吗" tabindex="-1">卷积可以从其他地方独立推导出来吗 <a class="header-anchor" href="#卷积可以从其他地方独立推导出来吗" aria-label="Permalink to &quot;卷积可以从其他地方独立推导出来吗&quot;">​</a></h2><p>可以。猫实验只是其中一条路，卷积从多个完全不同的角度都能推出来。</p><h3 id="路线一-从-效率-推导" tabindex="-1">路线一：从&quot;效率&quot;推导 <a class="header-anchor" href="#路线一-从-效率-推导" aria-label="Permalink to &quot;路线一：从&quot;效率&quot;推导&quot;">​</a></h3><p>全连接网络的问题：</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>1000×1000 的图片 = 100万像素</span></span>
<span class="line"><span>每个像素连到1000个神经元 = 10亿个参数</span></span>
<span class="line"><span>→ 根本训练不动</span></span></code></pre></div><p>为了减少参数，问两个问题：</p><ul><li>识别猫耳朵，真的需要看整张图吗？→ 不需要 → <strong>局部连接</strong></li><li>左上角和右下角的猫耳朵，检测方法一样吗？→ 一样 → <strong>权重共享</strong></li></ul><p>局部连接 + 权重共享 = 卷积。<strong>不需要猫，只需要想清楚&quot;怎么省参数&quot;就能推出来。</strong></p><h3 id="路线二-从-滑动平均-推导" tabindex="-1">路线二：从&quot;滑动平均&quot;推导 <a class="header-anchor" href="#路线二-从-滑动平均-推导" aria-label="Permalink to &quot;路线二：从&quot;滑动平均&quot;推导&quot;">​</a></h3><p>想平滑一组数据去掉噪声，最自然的想法：</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>每个点 = 自己和左右邻居的平均值</span></span>
<span class="line"><span>→ 拿窗口 [⅓, ⅓, ⅓] 在数据上滑动</span></span>
<span class="line"><span>→ 这就是卷积</span></span></code></pre></div><p>信号处理领域在神经科学之前几十年就用这个了。</p><h3 id="路线三-从-找模板-推导" tabindex="-1">路线三：从&quot;找模板&quot;推导 <a class="header-anchor" href="#路线三-从-找模板-推导" aria-label="Permalink to &quot;路线三：从&quot;找模板&quot;推导&quot;">​</a></h3><p>想在音频里找某个声音片段：</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>把模板在信号上逐位滑动</span></span>
<span class="line"><span>每个位置算一次相似度（点积）</span></span>
<span class="line"><span>相似度最高的地方就是匹配位置</span></span>
<span class="line"><span>→ 滑动 + 点积 = 卷积</span></span></code></pre></div><h3 id="路线四-从物理现象推导" tabindex="-1">路线四：从物理现象推导 <a class="header-anchor" href="#路线四-从物理现象推导" aria-label="Permalink to &quot;路线四：从物理现象推导&quot;">​</a></h3><p>很多自然现象天然就是卷积：</p><table tabindex="0"><thead><tr><th>现象</th><th>为什么是卷积</th></tr></thead><tbody><tr><td>图片模糊</td><td>每个像素 = 周围像素的加权平均</td></tr><tr><td>声音回声</td><td>此刻听到的 = 过去所有声音的加权叠加</td></tr><tr><td>热传导</td><td>某点温度 = 周围温度的扩散叠加</td></tr></tbody></table><h3 id="结论" tabindex="-1">结论 <a class="header-anchor" href="#结论" aria-label="Permalink to &quot;结论&quot;">​</a></h3><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>猫实验   →  局部感知   →  卷积（神经科学路线）</span></span>
<span class="line"><span>省参数   →  局部+共享  →  卷积（工程路线）</span></span>
<span class="line"><span>平滑数据 →  滑动窗口   →  卷积（统计路线）</span></span>
<span class="line"><span>找模板   →  滑动点积   →  卷积（信号处理路线）</span></span>
<span class="line"><span>物理方程 →  叠加原理   →  卷积（数学路线）</span></span></code></pre></div><p>卷积是一个&quot;必然会被发现&quot;的概念——不管从哪个方向出发，只要面对&quot;局部、重复、叠加&quot;这类问题，都会撞上它。猫实验只是其中一扇门。</p>`,79)])])}const b=s(p,[["render",l]]);export{u as __pageData,b as default};
